    input integer x;
    input integer y;
    begin max2 = (x > y) ? x : y; end
endfunction
function integer max4;
    input integer x;
    input integer y;
    input integer z;
    input integer w;
    begin max4 = max2(max2(x, y), max2(z, w)); end
endfunction
localparam LP_MAX4 = max4(1, 1, 0, 0);

